@startuml
skinparam handwritten true
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #f5f5f5
  BorderColor black
  ArrowColor black
}
skinparam note {
  BackgroundColor #f5f5f5
  BorderColor black
}

class Container {
  +__contains__(item)
}

class Iterable {
  +__iter__()
}

class Sized {
  +__len__(item)
}

class Collection {
}

class Mapping {
  +__getitem__(key)
  +keys()
  +items()
  +values()
  +get(key, default)
}

class MutableMapping {
  +__setitem__(key, value)
  +__delitem__(key)
}

class dict {
}

Container <|-- Collection
Iterable <|-- Collection
Sized <|-- Collection
Collection <|-- Mapping
Mapping <|-- MutableMapping
MutableMapping <|-- dict

note top of Container
  Please use '!option handwritten true' to enable handwritten
end note

@enduml
